#!/usr/bin/env node
/** install.js -- ARCHIVIO NAAF v17 */
const fs=require('fs'),path=require('path'),BASE=__dirname;
function w(r,b){const d=path.join(BASE,r);fs.mkdirSync(path.dirname(d),{recursive:true});fs.writeFileSync(d,Buffer.from(b,'base64'));console.log('  OK  '+r);}
console.log('\nARCHIVIO NAAF v17 -- Installazione...\n');
w('app.js',"");
w('package.json',"");
w('routes/mensile.js',"");
w('utils/pdfGenerator.js',"");
w('utils/pdfGeneratorPIA.js',"");
w('utils/pdfGeneratorColazione.js',"");
w('utils/archivioManager.js',"");
w('utils/ordiniVolo.js',"");
w('views/layouts/main.hbs',"");
w('views/mensile/index.hbs',"");
w('views/mensile/generi-conforto.hbs',"");
w('views/mensile/impostazioni.hbs',"");
w('views/mensile/pia.hbs',"");
w('views/mensile/colazione.hbs',"");
w('public/css/mensile.css',"");
w('config/personale.json',"");
w('config/tariffe.json',"");
['ARCHIVIO','views/partials','public/images'].forEach(d=>fs.mkdirSync(path.join(BASE,d),{recursive:true}));
console.log('\nv17 installata!');
console.log('Eseguire: npm install (per pdf-parse)');
console.log('Poi: npm start -> http://localhost:3001/mensile\n');